import React from 'react';
import Detector from './components/Detector';

function App() {
  return (
    <div className="App" style={{ minHeight: '100vh', backgroundColor: '#f4f7f6' }}>
      <header style={{ backgroundColor: '#1a2a3a', padding: '20px', color: 'white', textAlign: 'center' }}>
        <h1>NeuroScanAI Dashboard</h1>
      </header>
      <Detector />
    </div>
  );
}

export default App;
